  \choice validação de um vocábulo por uma instituição renomada.
  \choice concorrência entre línguas indígenas e a língua espanhola.
  \choice valorização da língua de um país em detrimento da de outro.
  \choice disputa entre hispano-americanos e espanhóis por sua origem.
\end{choices}

\question \begin{poem}
\verse{Cuando yo era chiquito}
\verse{todo quedaba cerca, cerquita.}
\verse{Para llegar al cielo}
\verse{no más bastaba una subidita.}
\verse{El sueño me alcanzaba}
\verse{para ir tan lejos como quería.}
\verse{Cuando yo era chiquito}
\verse{yo sí podía, yo sí podía.}
\verse{Libertad, libertad,}
\verse{libertad para mi niño.}
\verse{[...]}
\verse{Cuando yo era vejigo}
\verse{me iba pa’l río porque era hermoso,}
\verse{aunque estaba prohibido}
\verse{por peligroso, por peligroso.}
\verse{Como jagüey y ceiba,}
\verse{como la palma y la yagruma,}
\verse{cuando yo era vejigo}
\verse{yo era del monte y soñaba espuma.}
\verse{Libertad, libertad,}
\verse{libertad para mi niño.}
\end{poem}

\credits{RODRÍGUEZ, S. Cuando yo era un enano. In: Oh Melancolía. Havana: Empresa de Grabaciones y Ediciones Musicales, 1988 (fragmento).}

