  \choice apresentar uma carga semântica mítica.
  \CorrectChoice conservar elementos dos falares dos escravizados.
  \choice resgatar expressões portuguesas do período colonial.
  \choice decodificar o ritual religioso dos nossos antepassados.
  \choice favorecer a compreensão do léxico africano contemporâneo.
\end{choices}

