\question \begin{poem}
\verse{Pequenino morto}
\verse{Tange o sino, tange, numa voz de choro,}
\verse{Numa voz de choro... tão desconsolado...}
\verse{No caixão dourado, como em berço de ouro,}
\verse{Pequenino, levam-te dormindo... Acorda!}
\verse{Olha que te levam para o mesmo lado}
\verse{De onde o sino tange numa voz de choro...}
\verse{Pequenino, acorda!}
\verse{Que caminho triste, e que viagem! Alas}
\verse{De ciprestes negros a gemer no vento;}
\verse{Tanta boca aberta de famintas valas}
\verse{A pedir que as fartem, a esperar que as encham...}
\verse{Pequenino, acorda! Recupera o alento,}
\verse{Foge da cobiça dessas fundas valas}
\verse{A pedir que as encham.}
\end{poem}

\credits{CARVALHO, V. Poemas e canções. Rio de Janeiro: Saraiva, 1962 (fragmento).}

